$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$ff=Join-Path $root 'node_modules\ffmpeg-static\ffmpeg.exe';$src=Join-Path $root 'video-full';$dir=Join-Path $root 'video-fluid';$seg=Join-Path $dir 'segments';New-Item -ItemType Directory -Force $seg|Out-Null
# Parcours métier cohérent : connexion → fournisseur → IA/admin → client → commande → optimisation → impact.
$images=@('01','11','12','13','02','03','05','06','14','15','16','17','18','08','10','19')
for($i=0;$i-lt $images.Count;$i++){$img=Join-Path $src ($images[$i]+'.png');$clip=Join-Path $seg ('{0:D2}.mp4'-f($i+1));&$ff -loglevel error -y -loop 1 -framerate 25 -i $img -t 7.5 -vf "scale=1440:900,zoompan=z='min(zoom+0.00012,1.015)':d=188:s=1440x900:fps=25,format=yuv420p" -an -c:v libx264 -preset medium -crf 20 $clip;if($LASTEXITCODE-ne 0){throw "Segment $i"}}
$list=Join-Path $seg 'concat.txt';$c=1..16|ForEach-Object{"file '$((Join-Path $seg ('{0:D2}.mp4'-f$_)).Replace('\','/'))'"};[IO.File]::WriteAllLines($list,$c,[Text.UTF8Encoding]::new($false));$silent=Join-Path $dir 'silent.mp4';&$ff -loglevel error -y -f concat -safe 0 -i $list -c copy $silent
$audio=Join-Path $dir 'narration.mp3';$out=Join-Path $root 'Waste2Cash_Demo_Fluide_FR_2min.mp4';&$ff -loglevel error -y -i $silent -i $audio -filter_complex "[1:a]atempo=1.105,apad,atrim=0:119.88,afade=t=out:st=118.8:d=1[a]" -map '0:v:0' -map '[a]' -t 119.88 -c:v copy -c:a aac -b:a 160k -movflags +faststart $out;if($LASTEXITCODE-ne 0){throw 'Assemblage final'};Write-Output $out
